import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';

async function detectMemoryLoss(messages: any[]) {
  const historyLength = messages.length;
  const response = await streamText({
    model: openai('gpt-4o'),
    messages,
  });

  // Detect if context shrinks unexpectedly
  const stream = await response.toAIStreamResponse();
  console.log(`History length: ${historyLength}`);

  let contextTokens = 0;
  for await (const chunk of stream.textStream) {
    contextTokens += chunk.length;
  }

  if (contextTokens < historyLength * 10) {
    console.warn('🚨 Memory context loss detected');
  }
}

import { generateText } from 'ai';

function trackToolRepetition(messages: any[]) {
  const toolCalls = messages
    .filter((m: any) => m.role === 'assistant' && m.tool_calls)
    .flatMap((m: any) => m.tool_calls.map((tc: any) => tc.function.name));

  const uniqueTools = new Set(toolCalls);
  const repetitionRate = (toolCalls.length - uniqueTools.size) / toolCalls.length;

  if (repetitionRate > 0.3) {
    console.error(`🔄 Tool repetition detected: ${repetitionRate.toFixed(2)}`);
    return false;
  }
  return true;
}

