function MemoryOverflowDetector({ messages }: { messages: any[] }) {
  const totalTokens = messages.reduce((sum, msg) => sum + msg.content.length, 0);

  if (totalTokens > 128000) {
    console.error('💥 Memory buffer approaching limit:', totalTokens);
    // Trim oldest messages
    return messages.slice(-20);
  }

  const { messages: chatMessages, append } = useChat();
  return null;
}

