import { kv } from '@vercel/kv';
import { streamText } from 'ai';

import { openai } from '@ai-sdk/openai';

async function agentWithMemory(sessionId: string, newMessage: string) {
  // Load persistent memory
  const history = await kv.lrange(`chat:${sessionId}`, 0, -1) as any[];
  const messages = [...history, { role: 'user', content: newMessage }];

  const result = await streamText({
    model: openai('gpt-4o'),
    messages,
    maxTokens: 4000,
  });

  // Persist updated history
  await kv.lpush(`chat:${sessionId}`, ...messages.slice(-50));
  await kv.ltrim(`chat:${sessionId}`, 0, 49);

  return result;
}

function trimMemory(messages: any[], maxTokens = 120000): any[] {
  let totalTokens = 0;
  const trimmed: any[] = [];

  // Keep last 10 messages + summarize older ones
  for (let i = Math.max(0, messages.length - 10); i < messages.length; i++) {
    const msg = messages[i];
    const msgTokens = msg.content.length / 4 + 100;

    if (totalTokens + msgTokens > maxTokens) {
      // Summarize overflow
      trimmed.unshift({
        role: 'system',
        content: `Previous conversation summary: ${totalTokens} tokens compressed`
      });
      break;
    }

    trimmed.push(msg);
    totalTokens += msgTokens;
  }

  return [{ role: 'system', content: 'Use conversation history context.' }, ...trimmed];
}

// Use in generateText/streamText
await streamText({ model, messages: trimMemory(messages) });

import { useChat } from 'ai/react';
import { kv } from '@vercel/kv';

function useMemoryChat(sessionId: string) {
  const { messages, append, ...rest } = useChat();

  // Sync to KV on message append
  const appendWithMemory = async (msg: any) => {
    await append(msg);
    await kv.lpush(`chat:${sessionId}`, msg);
    await kv.ltrim(`chat:${sessionId}`, 0, 49);
  };

  // Load on mount
  React.useEffect(() => {
    kv.lrange(`chat:${sessionId}`, 0, -1).then(history => {
      history.forEach(msg => append(msg as any, false));
    });
  }, []);

  return { messages, append: appendWithMemory, ...rest };
}

